local surf = { }\\r\\\
surface.surf = surf\\r\\\
\\r\\\
local table_concat, math_floor, math_atan2 = table.concat, math.floor, math.atan2\\r\\\
\\r\\\
local _cc_color_to_hex, _cc_hex_to_color = { }, { }\\r\\\
for i = 0, 15 do\\r\\\
