local function calcStack(stack, width, height)\\r\\\
	local ox, oy, cx, cy, cwidth, cheight = 0, 0, 0, 0, width, height\\r\\\
	for i = 1, #stack do\\r\\\
		ox = ox + stack[i].ox\\r\\\
		oy = oy + stack[i].oy\\r\\\
		cx = cx + stack[i].x\\r\\\
		cy = cy + stack[i].y\\r\\\
		cwidth = stack[i].width\\r\\\
		cheight = stack[i].height\\r\\\
	end\\r\\\
	return ox, oy, cx, cy, cwidth, cheight\\r\\\
end\\r\\\
\\r\\\
local function clipRect(x, y, width, height, cx, cy, cwidth, cheight)\\r\\\
	if x < cx then\\r\\\
		width = width + x - cx\\r\\\
		x = cx\\r\\\
	end\\r\\\
	if y < cy then\\r\\\
		height = height + y - cy\\r\\\
		y = cy\\r\\\
	end\\r\\\
	if x + width > cx + cwidth then\\r\\\
		width = cwidth + cx - x\\r\\\
	end\\r\\\
	if y + height > cy + cheight then\\r\\\
		height = cheight + cy - y\\r\\\
	end\\r\\\
	return x, y, width, height\\r\\\
