function surface.create(width, height, b, t, c)\\r\\\
	local surface = setmetatable({ }, {__index = surface.surf})\\r\\\
	surface.width = width\\r\\\
	surface.height = height\\r\\\
	surface.buffer = { }\\r\\\
	surface.overwrite = false\\r\\\
	surface.stack = { }\\r\\\
	surface.ox, surface.oy, surface.cx, surface.cy, surface.cwidth, surface.cheight = calcStack(surface.stack, width, height)\\r\\\
	-- force array indeces instead of hashed indices\\r\\\
\\r\\\
	local buffer = surface.buffer\\r\\\
	for i = 1, width * height * 3, 3 do\\r\\\
		buffer[i] = b or false\\r\\\
		buffer[i + 1] = t or false\\r\\\
		buffer[i + 2] = c or false\\r\\\
	end\\r\\\
	buffer[width * height * 3 + 1] = false\\r\\\
	if not b then\\r\\\
		for i = 1, width * height * 3, 3 do\\r\\\
			buffer[i] = b\\r\\\
		end\\r\\\
	end\\r\\\
	if not t then\\r\\\
		for i = 2, width * height * 3, 3 do\\r\\\
			buffer[i] = t\\r\\\
		end\\r\\\
	end\\r\\\
	if not c then\\r\\\
		for i = 3, width * height * 3, 3 do\\r\\\
			buffer[i] = c\\r\\\
		end\\r\\\
	end\\r\\\
\\r\\\
	return surface\\r\\\
end\\r\\\
\\r\\\
function surface.getPlatformOutput(output)\\r\\\
	output = output or (term or gpu or (love and love.graphics) or io)\\r\\\
\\r\\\
	if output.blit and output.setCursorPos then\\r\\\
		return \\\"cc\\\", output, output.getSize()\\r\\\
