	end\\r\\\
end\\r\\\
\\r\\\
function surf:output(output, x, y, sx, sy, swidth, sheight)\\r\\\
	local platform, output, owidth, oheight = surface.getPlatformOutput(output)\\r\\\
\\r\\\
	x = x or 0\\r\\\
