			end\\r\\\
		end\\r\\\
		output.setColor((r or 0) * 255, (g or 0) * 255, (b or 0) * 255, (r or g or b) and 255 or 0)\\r\\\
		output.points(pos)\\r\\\
\\r\\\
	elseif platform == \\\"redirection\\\" then\\r\\\
